insert into public.advertising_requests (title, description, city, category, budget, duration, contact_phone, contact_email) values
  ('Սրճի բրենդի արշավ', 'Փնտրում ենք Երևանի կենտրոնում մեկնող ավտոմեքենաներ սրճի բրենդի ստիկերներ տեղադրելու համար։', 'Yerevan', 'cars', 500, '3 ամիս', '+37491123456', 'campaign@coffeebrand.am'),
  ('Էներգետիկ ըմպելիքների գովազդ', 'Անհրաժեշտ են բարձր տեսանելիություն ունեցող ավտոմեքենաներ և ֆուրգոններ քաղաքային մարշրուտներով։', 'Yerevan', 'cars', 800, '6 ամիս', '+37492123456', 'marketing@energy.am'),
  ('Նոր բնակ complex-ի գովազդ', 'Փնտրում ենք խոշոր պատեր կամ շենքերի ճակատներ գլխավոր ճանապարհների դիմաց։', 'Yerevan', 'buildings', 1200, '12 ամիս', '+37493123456', 'sales@developer.am'),
  ('Սուպերմարկետի ցուցափեղկ', 'Փնտրում ենք խանութի ցուցափեղկ կամ մուտքի պատ հիմնական փողոցում, բարձր հետիոտնային հոսքով։', 'Gyumri', 'shop_windows', 350, '6 ամիս', '+37494123456', 'ads@supermarket.am'),
  ('Տաքսի ծառայության ստիկերներ', 'Փնտրում ենք տաքսի նավատորմ դռների պանելների գովազդի համար։ Երևանի և մարզերի մարշրուտներ։', 'Yerevan', 'cars', 400, '3 ամիս', '+37495123456', 'partners@taxi.am'),
  ('Կուրյերների համազգեստի գովազդ', 'Փնտրում ենք արագ առաքման սկուտեր/մոտոցիկլետներ քաղաքով մեկ տեսանելիության համար։', 'Yerevan', 'couriers', 600, '6 ամիս', '+37496123456', 'branding@delivery.am'),
  ('Ռեստորանի արշավ', 'Փնտրում ենք պատշգամբ կամ ցուցափեղկ գլխավոր փողոցում, զբոսաշրջիկների հոսք ունեցող տեղանք։', 'Dilijan', 'balconies', 280, '4 ամիս', '+37497123456', 'promo@restaurant.am'),
  ('Բեռնատարների ամբողջական փաթաթում', 'Փնտրում ենք բեռնատարներ կամ ֆուրգոններ ամբողջական փաթաթման համար։ Մայրուղիներ և քաղաքային մարշրուտներ։', 'Yerevan', 'trucks', 1500, '12 ամիս', '+37498123456', 'fleet@logistics.am'),
  ('Դեղատան ցուցափեղկ', 'Փնտրում ենք դեղատան կամ բժշկական կենտրոնի ցուցափեղկ բնակելի թաղամասում։', 'Vanadzor', 'shop_windows', 220, '3 ամիս', '+37499123456', 'pharma@health.am'),
  ('Ֆինանսական ծառայությունների պատ', 'Փնտրում ենք խոշոր պատ կամ շենքի ճակատ ֆինանսական թաղամասում։', 'Yerevan', 'walls', 950, '6 ամիս', '+37410123456', 'media@bank.am'),
  ('Սպորտային ապրանքանիշի արշավ', 'Փնտրում ենք ավտոմեքենաներ, պատեր և ցուցափեղկներ սպորտային իրադարձությունների շրջակայքում։', 'Yerevan', 'cars', 700, '4 ամիս', '+37410223456', 'events@sportbrand.am'),
  ('Զբոսաշրջության գովազդ', 'Փնտրում ենք տեսանելի հարթակներ Դիլիջան, Գյումրի, Վանաձոր — զբոսաշրջիկների հոսք ունեցող վայրեր։', 'Dilijan', 'other', 450, '6 ամիս', '+37410323456', 'tourism@armenia.am'),
  ('Կրթական կենտրոնի ցուցանակ', 'Փնտրում ենք ցուցափեղկ կամ պատ համալսարանական թաղամասում։', 'Yerevan', 'shop_windows', 300, '5 ամիս', '+37410423456', 'info@edu.am'),
  ('Ավտոսրահի գովազդ', 'Փնտրում ենք ավտոմեքենաներ ամբողջական փաթաթումով կամ դռների պանելներ։ Պրեմիում image։', 'Yerevan', 'cars', 1100, '12 ամիս', '+37410523456', 'dealer@autoshow.am'),
  ('Տեղական արտադրության մթերք', 'Փնտրում ենք խանութի ցուցափեղկ կամ պատ շուկայի/սուպերմարկետի մոտ։', 'Abovyan', 'shop_windows', 180, '3 ամիս', '+37410623456', 'local@food.am');
